import { units } from '@dynatrace-sdk/units';

const stringToSDK = new Map<string, object>([
  ['bit', { input: units.data.bit, abbreviate: false }],
  ['byte', { input: units.data.byte }],
  ['duration', { input: units.time.millisecond }],
  ['percent', { input: units.percentage.percent }],
  ['number', {}],
  ['rate', { abbreviate: false }],
  ['date', {}],
]);

export function getFormatterDefinition(unit: string) {
  const def = stringToSDK.get(unit);
  return def ?? { suffix: unit };
}
